mapper.select:
select id, user_name, latest_message, priority_level, status, update_time, created_at, updated_at, created_by, updated_by, deleted from service_tickets
and deleted = false
and (user_name like concat('%', #{keyword}, '%') or latest_message like concat('%', #{keyword}, '%'))
and status = #{status}
order by id asc limit #{pageSize} offset #{offset}

mapper.update:
update service_tickets
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where id = #{id}
  and deleted = false
